sql:
SELECT reward_type
FROM rewards
WHERE reward_value = (SELECT MAX(reward_value) FROM rewards);

SELECT COUNT(*) AS total_players,
       AVG(num_achievements) AS avg_achievements
FROM (
  SELECT player_id, COUNT(*) AS num_achievements
  FROM player_achievements
  WHERE achievement_id IN (
    SELECT achievement_id FROM game_achievements WHERE game_id = (SELECT game_id FROM games WHERE game_name = 'Game of Thrones')
  )
  GROUP BY player_id
) AS player_achievement_counts;

SELECT player_id 
FROM player_achievements 
WHERE achievement_id = 1;

SELECT achievement_id, description_lang
FROM achievements
WHERE parent_id IS NULL AND repeatable = 1;

external_knowledge:
- 'masters of the game' refers to players who have the 'VIEW_ACHIEVEMENT' permission; 
- 'own an API key' means players who have an API key associated with their account; 
- 'unlock hidden treasures' refers to the achievements that are not hidden and are visible to players with the 'VIEW_ACHIEVEMENT' permission.

sql:
SELECT p.player_name
FROM players p
JOIN player_achievements pa ON p.player_id = pa.player_id;

SELECT MAX(amount) 
FROM achievements 
WHERE description_lang = 'Most gold ever owned:';

SELECT achievement_type
FROM achievements
WHERE amount = (SELECT MAX(amount) FROM achievements);

SELECT DISTINCT achievement_id
FROM game_achievements
WHERE game_id = 1;

SELECT achievement_id, description_lang 
FROM achievements 
WHERE achievement_id = 0;

SELECT COUNT(DISTINCT player_id) 
FROM user_roles
WHERE role_id = (SELECT role_id FROM roles WHERE role_name = 'Developer');

SELECT achievement_id
FROM achievements
WHERE amount = (SELECT MAX(amount) FROM achievements);

SELECT MAX(role_count) AS max_user_roles
FROM (
  SELECT COUNT(*) AS role_count
  FROM user_roles
  GROUP BY player_id
) AS role_counts;
